import React from 'react';
import { motion } from 'framer-motion';
import { ShoppingCart, Flame } from 'lucide-react';
import Button from './Button';
import useCartStore from '../store/cartStore';

const MealCard = ({ meal }) => {
  const addItem = useCartStore((state) => state.addItem);

  const handleAddToCart = () => {
    addItem(meal);
  };

  // Nutrition badges with icons and colors
  const nutritionBadges = [
    {
      label: 'Protein',
      value: meal.protein,
      unit: 'g',
      color: 'bg-blue-100 text-blue-700',
      icon: '💪',
    },
    {
      label: 'Carbs',
      value: meal.carbs,
      unit: 'g',
      color: 'bg-orange-100 text-orange-700',
      icon: '🌾',
    },
    {
      label: 'Fiber',
      value: meal.fiber,
      unit: 'g',
      color: 'bg-green-100 text-green-700',
      icon: '🌿',
    },
  ];

  const containerVariants = {
    hidden: { opacity: 0, y: 20 },
    visible: {
      opacity: 1,
      y: 0,
      transition: { duration: 0.5 },
    },
  };

  const imageVariants = {
    hover: {
      scale: 1.08,
      transition: { duration: 0.3, ease: 'easeInOut' },
    },
  };

  return (
    <motion.div
      initial="hidden"
      whileInView="visible"
      variants={containerVariants}
      whileHover={{ y: -12 }}
      className="bg-white rounded-3xl overflow-hidden shadow-lg hover:shadow-2xl transition-all duration-300 flex flex-col h-full"
    >
      {/* Image Container with Overlay */}
      <motion.div
        className="relative h-48 sm:h-56 md:h-48 lg:h-56 bg-gradient-to-br from-neutral-bg to-gray-100 overflow-hidden group"
        whileHover="hover"
      >
        <motion.img
          src={meal.image || 'https://via.placeholder.com/300x200?text=Meal'}
          alt={meal.name}
          className="w-full h-full object-cover"
          variants={imageVariants}
        />

        {/* Calories Badge */}
        {meal.calories && (
          <motion.div
            initial={{ opacity: 0, scale: 0.8 }}
            whileInView={{ opacity: 1, scale: 1 }}
            className="absolute top-3 right-3 bg-gradient-to-r from-red-500 to-red-600 text-white px-3 py-1.5 rounded-full text-xs sm:text-sm font-bold flex items-center gap-1 shadow-lg"
          >
            <Flame size={14} />
            <span>{meal.calories}</span>
            <span className="text-xs">cal</span>
          </motion.div>
        )}

        {/* Category Badge */}
        <motion.div
          initial={{ opacity: 0, scale: 0.8 }}
          whileInView={{ opacity: 1, scale: 1 }}
          transition={{ delay: 0.1 }}
          className="absolute top-3 left-3 bg-white/90 backdrop-blur-sm text-dark-text px-3 py-1.5 rounded-full text-xs font-semibold shadow-md"
        >
          {meal.category}
        </motion.div>
      </motion.div>

      {/* Content Section */}
      <div className="p-4 sm:p-5 md:p-4 lg:p-5 flex flex-col flex-grow">
        {/* Meal Name */}
        <h3 className="font-poppins font-bold text-base sm:text-lg md:text-base lg:text-lg text-dark-text mb-2 line-clamp-2 leading-tight">
          {meal.name}
        </h3>

        {/* Description */}
        {meal.description && (
          <p className="text-gray-600 text-xs sm:text-sm md:text-xs lg:text-sm mb-3 line-clamp-2 leading-relaxed">
            {meal.description}
          </p>
        )}

        {/* Nutrition Badges */}
        <div className="flex flex-wrap gap-2 mb-4">
          {nutritionBadges.map((badge) => (
            <motion.div
              key={badge.label}
              whileHover={{ scale: 1.05 }}
              className={`${badge.color} px-2.5 py-1.5 rounded-full text-xs font-semibold flex items-center gap-1 transition-all duration-200`}
            >
              <span>{badge.icon}</span>
              <span>{badge.value}</span>
              <span className="text-xs opacity-75">{badge.unit}</span>
            </motion.div>
          ))}
        </div>

        {/* Price Section */}
        <div className="flex items-center justify-between mb-4 mt-auto">
          <div className="flex items-baseline gap-1">
            <span className="text-2xl sm:text-3xl md:text-2xl lg:text-3xl font-poppins font-bold text-primary">
              ₹{meal.price}
            </span>
          </div>
        </div>

        {/* Add to Cart Button */}
        <motion.div
          whileHover={{ scale: 1.02 }}
          whileTap={{ scale: 0.98 }}
          className="w-full"
        >
          <Button
            variant="primary"
            size="md"
            className="w-full flex items-center justify-center gap-2 text-sm sm:text-base"
            onClick={handleAddToCart}
          >
            <ShoppingCart size={18} />
            <span>Add to Cart</span>
          </Button>
        </motion.div>
      </div>
    </motion.div>
  );
};

export default MealCard;
